// src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ToastProvider } from './context/ToastContext';
import { LoadingProvider } from './context/LoadingContext';
import { RoleProvider } from './context/RoleContext';
import MasterAdminDashboard from './pages/admin/MasterAdminDashboard';
import ErrorBoundary from './components/common/ErrorBoundary';
import HomePage from './pages/HomePage';
import LoginPage from './pages/LoginPage';
import RegisterPage from './pages/RegisterPage';
import DashboardPage from './pages/DashboardPage';
import ProfilePage from './pages/ProfilePage';
import RoleBasedNav from './components/common/RoleBasedNav';
import PatientList from './components/doctor/PatientList';
import PrescriptionList from './components/prescriptions/PrescriptionList';
import './styles/App.css';

// Protected Route component
const ProtectedRoute = ({ children, requiredRole }) => {
    const { user, loading } = useAuth();
    
    if (loading) {
        return <div className="loading">Loading...</div>;
    }
    
    if (!user) {
        return <Navigate to="/login" />;
    }
    
    // Check if route requires a specific role
    if (requiredRole && user.role !== requiredRole) {
        return <Navigate to="/dashboard" />;
    }
    
    return children;
};

// Public Route component
const PublicRoute = ({ children }) => {
    const { user, loading } = useAuth();
    
    if (loading) {
        return <div className="loading">Loading...</div>;
    }
    
    return !user ? children : <Navigate to="/dashboard" />;
};

function AppContent() {
    const { user } = useAuth();
    
    return (
        <div className="app">
            <header className="app-header">
                <h1>🏥 E-Health System</h1>
            </header>
            
            {/* Role-based navigation - only show when user is logged in */}
            {user && <RoleBasedNav />}
            
            <main className="app-main">
                <Routes>
                    {/* Public Routes */}
                    <Route path="/" element={<HomePage />} />
                    <Route path="/login" element={
                        <PublicRoute>
                            <LoginPage />
                        </PublicRoute>
                    } />
                    <Route path="/register" element={
                        <PublicRoute>
                            <RegisterPage />
                        </PublicRoute>
                    } />
                    
                    {/* Protected Routes - Patient & Doctor */}
                    <Route path="/dashboard" element={
                        <ProtectedRoute>
                            <DashboardPage />
                        </ProtectedRoute>
                    } />
                    <Route path="/profile" element={
                        <ProtectedRoute>
                            <ProfilePage />
                        </ProtectedRoute>
                    } />
                    
                    {/* Doctor-Only Routes */}
                    <Route path="/patients" element={
                        <ProtectedRoute requiredRole="doctor">
                            <PatientList />
                        </ProtectedRoute>
                    } />
                    <Route path="/prescriptions" element={
                        <ProtectedRoute>
                            <PrescriptionList />
                        </ProtectedRoute>
                    } />
                    
                    {/* Fallback Route */}
                    <Route path="*" element={<Navigate to="/" replace />} />
                </Routes>
            </main>
            
            {/* Simple Footer */}
            <footer className="app-footer">
                <div className="footer-content">
                    <p>&copy; 2025 E-Health System. All rights reserved.</p>
                    <p>Secure Electronic Health Records with Fingerprint Authentication</p>
                </div>
            </footer>
        </div>
    );
}

// Wrap the app content
function App() {
    return (
        <ErrorBoundary>
            <Router>
                <AuthProvider>
                    <RoleProvider>
                        <ToastProvider>
                            <LoadingProvider>
                                <AppContent />
                            </LoadingProvider>
                        </ToastProvider>
                    </RoleProvider>
                </AuthProvider>
            </Router>
        </ErrorBoundary>
    );
}

export default App;
